definitions.inputs:
={{((parameters) => {
    const CHECKS = ['nsfw', 'topicalAlignment', 'custom', 'jailbreak'];
    const checks = Object.keys(parameters?.guardrails ?? {});
    const hasLLMChecks = checks.some((check) => CHECKS.includes(check));
    if (!hasLLMChecks) {
        return ['main'];
    }
    return [
        'main',
        {
            type: 'ai_languageModel',
            displayName: 'Chat Model',
            maxConnections: 1,
            required: true,
            filter: {
                excludedNodes: [
                    '@n8n/n8n-nodes-langchain.lmCohere',
                    '@n8n/n8n-nodes-langchain.lmOllama',
                    'n8n/n8n-nodes-langchain.lmOpenAi',
                    '@n8n/n8n-nodes-langchain.lmOpenHuggingFaceInference',
                ],
            },
        },
    ];
})($parameter)}}

definitions.outputs:
={{
		((parameters) => {
			const operation = parameters.operation ?? 'classify';

			if (operation === 'classify') {
				return [{displayName: "Pass", type: "main"}, {displayName: "Fail", type: "main"}]
			}

			return [{ displayName: "", type: "main"}]
		})($parameter)
	}}

